import React, { Component } from "react";
import ReactDOM from "react-dom";

class Creator extends Component {

    constructor(props) {
        super(props)
        this.state = {
            innerHTML: (
                <>
                    <div className="container">

                    </div>
                </>
            )
        }
    }

    render() {
        return (
            <div className="container">
                { this.state.innerHTML }
            </div>
        )
    }
}

ReactDOM.render(
    <Creator />,
    document.querySelector('#App')
)
